import json
import pymysql
from sqlalchemy import create_engine, text

def lambda_handler(event, context):
    # Database connection details
    db_host = 'your_db_host'
    db_user = 'your_db_user'
    db_password = 'your_db_password'
    db_name = 'your_db_name'

    # Create a SQLAlchemy engine
    engine = create_engine(f'mysql+pymysql://{db_user}:{db_password}@{db_host}/{db_name}')

    # Extract search parameters from the event
    search_params = event.get('queryStringParameters', {})

    # Build SQL query dynamically based on search parameters
    query_parts = ['SELECT * FROM products']
    conditions = []

    for key, value in search_params.items():
        conditions.append(f"{key} LIKE :{key}")

    if conditions:
        query_parts.append('WHERE ' + ' AND '.join(conditions))

    full_query = ' '.join(query_parts)

    # Execute the query
    with engine.connect() as connection:
        result = connection.execute(text(full_query), search_params)
        rows = result.fetchall()

    # Prepare response
    response = {
        'statusCode': 200,
        'body': json.dumps([dict(row) for row in rows])
    }

    return response